package org.eclipse.rdf4j.workbench.commands;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.times;
import static org.mockito.Mockito.verify;

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicReference;

import javax.servlet.AsyncContext;

import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.junit.jupiter.api.Test;

class AsyncExplainRegistryTest {

	@Test
	void registerRejectsDuplicateIdsAndForgetRemovesHandle() {
		AsyncExplainRegistry registry = new AsyncExplainRegistry(Executors.newSingleThreadExecutor());
		AsyncContext asyncContext = mock(AsyncContext.class);
		AsyncExplainRegistry.Handle handle = registry.register("req-1", asyncContext, null);

		assertThatThrownBy(() -> registry.register("req-1", asyncContext, null))
				.isInstanceOf(IllegalStateException.class)
				.hasMessage("Explain request already active: req-1");

		registry.forget(handle);

		assertThat(registry.cancel("req-1")).isFalse();
		registry.shutdown();
	}

	@Test
	void cancelInterruptsWorkerClosesConnectionRunsRemoteCancelAndCompletesAsyncContext() {
		AsyncExplainRegistry registry = new AsyncExplainRegistry(Executors.newSingleThreadExecutor());
		AsyncContext asyncContext = mock(AsyncContext.class);
		RepositoryConnection connection = mock(RepositoryConnection.class);
		AtomicBoolean remoteCancelled = new AtomicBoolean(false);
		RecordingThread worker = new RecordingThread();
		AsyncExplainRegistry.Handle handle = registry.register("req-2", asyncContext,
				() -> remoteCancelled.set(true));
		handle.attach(worker, connection);

		assertThat(handle.getAsyncContext()).isSameAs(asyncContext);
		assertThat(handle.isActive()).isTrue();

		assertThat(registry.cancel("req-2")).isTrue();

		assertThat(worker.interrupted).isTrue();
		assertThat(handle.isActive()).isFalse();
		assertThat(remoteCancelled.get()).isTrue();
		verify(connection).close();
		verify(asyncContext).complete();

		handle.cancel();
		verify(asyncContext, times(2)).complete();
		registry.shutdown();
	}

	@Test
	void cancelSwallowsSecondaryFailures() {
		AsyncExplainRegistry registry = new AsyncExplainRegistry(Executors.newSingleThreadExecutor());
		AsyncContext asyncContext = mock(AsyncContext.class);
		RepositoryConnection connection = mock(RepositoryConnection.class);
		doThrow(new RuntimeException("close")).when(connection).close();
		RuntimeException remoteFailure = new RuntimeException("remote");
		doThrow(new IllegalStateException("done")).when(asyncContext).complete();

		AsyncExplainRegistry.Handle handle = registry.register("req-3", asyncContext, () -> {
			throw remoteFailure;
		});
		handle.attach(new RecordingThread(), connection);

		handle.cancel();

		assertThat(handle.isActive()).isFalse();
		registry.shutdown();
	}

	@Test
	void completeAndShutdownFinishActiveHandlesAndUseNamedDaemonThreads() throws Exception {
		CountDownLatch executed = new CountDownLatch(1);
		AtomicReference<String> threadName = new AtomicReference<>();
		AtomicBoolean daemon = new AtomicBoolean(false);
		AsyncExplainRegistry registry = new AsyncExplainRegistry();
		AsyncContext asyncContext = mock(AsyncContext.class);
		AsyncExplainRegistry.Handle handle = registry.register("req-4", asyncContext, null);

		registry.execute(() -> {
			threadName.set(Thread.currentThread().getName());
			daemon.set(Thread.currentThread().isDaemon());
			executed.countDown();
		});

		assertThat(executed.await(5, TimeUnit.SECONDS)).isTrue();
		assertThat(threadName.get()).startsWith("rdf4j-workbench-explain-");
		assertThat(daemon.get()).isTrue();

		registry.complete(handle);
		verify(asyncContext).complete();
		assertThat(registry.cancel("req-4")).isFalse();

		AsyncContext otherContext = mock(AsyncContext.class);
		registry.register("req-5", otherContext, null);
		registry.shutdown();
		verify(otherContext).complete();
	}

	private static final class RecordingThread extends Thread {
		private boolean interrupted;

		@Override
		public void interrupt() {
			interrupted = true;
		}
	}
}
